const input = $input.first().json;

const body = {
  model: input.model,
  max_tokens: input.max_tokens,
  system: [
    {
      type: 'text',
      text: input.system,
      cache_control: { type: 'ephemeral' }
    }
  ],
  messages: [
    { role: 'user', content: input.user_message }
  ]
};

console.log(`[Call LLM/Anthropic] Building request for model: ${input.model}, system: ${(input.system || '').length} chars (cache-marked)`);

return [{
  json: {
    request_body: body,
    provider: 'anthropic',
    model: input.model
  }
}];

// Normalize Anthropic response into provider-agnostic shape
// Mode: Run Once for All Items
// Cost is NOT computed here â€” pricing lives in the pricing sheet and is applied by Log Job Result

const claudeResponse = $input.first().json;
const buildRequest = $('Build Anthropic Request').first().json;

const content = claudeResponse.content?.[0]?.text || '';
const usage = claudeResponse.usage || {};

const inputTokens = usage.input_tokens || 0;
const outputTokens = usage.output_tokens || 0;
const cachedInputTokens = usage.cache_read_input_tokens || 0;
const cacheWriteTokens = usage.cache_creation_input_tokens || 0;

const modelUsed = claudeResponse.model || buildRequest.model;

const success = content.length > 0;
const errors = success ? [] : ['Empty response from Anthropic'];

console.log(`[Call LLM/Anthropic] Response: ${content.length} chars | tokens: ${inputTokens}in + ${outputTokens}out + ${cachedInputTokens}cached + ${cacheWriteTokens}cache_write | model: ${modelUsed}`);

return [{
  json: {
    success,
    content,
    input_tokens: inputTokens,
    output_tokens: outputTokens,
    cached_input_tokens: cachedInputTokens,
    cache_write_tokens: cacheWriteTokens,
    model_used: modelUsed,
    provider_used: 'anthropic',
    errors
  }
}];

// Fallback for providers we haven't implemented yet
// Mode: Run Once for All Items

const input = $input.first().json;
const provider = input.provider || 'unknown';

const errorMsg = `Provider "${provider}" is not yet implemented in Call LLM. Currently supported: anthropic. Add a new branch in Call LLM to support this provider.`;

console.error(`[Call LLM] ${errorMsg}`);

return [{
  json: {
    success: false,
    content: '',
    input_tokens: 0,
    output_tokens: 0,
    cost_estimate: 0,
    model_used: input.model || 'unknown',
    provider_used: provider,
    errors: [errorMsg]
  }
}];

// Call LLM Set Inputs â€” CANONICAL VERSION
// Mode: Run Once for All Items
// Handles both Manual Trigger and Execute Workflow Trigger
// Defensively strips '=' prefix that n8n adds when crossing Execute Workflow boundaries
// Normalizes provider (trim + lowercase) and model (trim) so downstream nodes
// see clean values regardless of config whitespace/case.

const trigger = $input.first()?.json || {};

// DEBUG: log raw trigger
console.log(`[Call LLM Set Inputs] Raw trigger keys: ${Object.keys(trigger).join(', ')}`);
console.log(`[Call LLM Set Inputs] Raw max_tokens: ${JSON.stringify(trigger.max_tokens)} (type: ${typeof trigger.max_tokens})`);

// Strip leading '=' that n8n sometimes adds to expression-resolved values
const stripEquals = (val) => {
  if (typeof val === 'string' && val.startsWith('=')) {
    return val.substring(1);
  }
  return val;
};

const TEST_DEFAULTS = {
  provider: 'anthropic',
  model: 'claude-haiku-4-5-20251001',
  system: 'You are a helpful assistant.',
  user_message: 'Say hello in 5 words.',
  max_tokens: 50
};

const usingDefaults = !trigger.provider;

const provider = String(stripEquals(trigger.provider) || TEST_DEFAULTS.provider).trim().toLowerCase();
const model = String(stripEquals(trigger.model) || TEST_DEFAULTS.model).trim();
const system = stripEquals(trigger.system) || TEST_DEFAULTS.system;
const userMessage = stripEquals(trigger.user_message) || TEST_DEFAULTS.user_message;
const maxTokensStripped = stripEquals(trigger.max_tokens);
const maxTokens = Number(maxTokensStripped) || TEST_DEFAULTS.max_tokens;

console.log(`[Call LLM Set Inputs] After Number() â€” max_tokens: ${maxTokens} (type: ${typeof maxTokens})`);

if (usingDefaults) {
  console.log('[Call LLM] No trigger payload â€” using test defaults');
}

console.log(`[Call LLM] Provider: ${provider}, Model: ${model}, max_tokens: ${maxTokens}`);

return [{
  json: {
    provider,
    model,
    system,
    user_message: userMessage,
    max_tokens: maxTokens
  }
}];

// Build OpenAI Request
// Mode: Run Once for All Items
// Canonical inputs â†’ OpenAI Chat Completions request body.
// OpenAI caching is automatic for prompts â‰¥1024 tokens; no cache_control needed.

const input = $input.first().json;

const body = {
  model: input.model,
  messages: [
    { role: 'system', content: input.system },
    { role: 'user', content: input.user_message }
  ],
  max_completion_tokens: input.max_tokens
};

console.log(`[Call LLM/OpenAI] Building request for model: ${input.model}, system: ${(input.system || '').length} chars, max_completion_tokens: ${input.max_tokens}`);

return [{
  json: {
    request_body: body,
    provider: 'openai',
    model: input.model
  }
}];

// Build Error Response (Anthropic)
// Mode: Run Once for All Items
// Fires when HTTP Request to Anthropic fails after all retries are exhausted.
// Emits the same shape as Normalize Anthropic Response so downstream agents see uniform output.
const errItem = $input.first()?.json || {};
const setInputs = $('Set Inputs').first().json;
// Anthropic API errors come back as: { type: 'error', error: { type: '...', message: '...' } }
// n8n network/timeout errors flatten differently â€” defensive reads handle both.
const errorType =
  errItem?.error?.type ||
  errItem?.type ||
  errItem?.code ||
  'unknown_error';
const errorMessage =
  errItem?.error?.message ||
  errItem?.message ||
  'Unknown LLM API error';
// n8n wraps provider errors as NodeApiError: the real provider text (e.g. the
// credit-balance message) lands in error.description, not error.message.
const errorDescription =
  errItem?.error?.description ||
  errItem?.description ||
  '';
const httpCode =
  errItem?.error?.httpCode ||
  errItem?.statusCode ||
  errItem?.httpCode ||
  null;
// Categorize for downstream handling and logging.
// Match against BOTH message and description â€” the credit-balance text lives in
// description when n8n wraps the provider error as NodeApiError.
let category = 'unknown';
const msgLower = `${String(errorMessage)} ${String(errorDescription)}`.toLowerCase();
if (
  msgLower.includes('credit balance') ||
  msgLower.includes('insufficient') ||
  msgLower.includes('billing') ||
  msgLower.includes('quota')
) {
  category = 'insufficient_credit';
} else if (
  errorType === 'authentication_error' ||
  errorType === 'permission_error' ||
  httpCode === 401 ||
  httpCode === 403
) {
  category = 'invalid_api_key';
} else if (errorType === 'rate_limit_error' || httpCode === 429) {
  category = 'rate_limit';
} else if (errorType === 'overloaded_error' || httpCode === 529) {
  category = 'provider_overloaded';
} else if (
  errorType === 'ETIMEDOUT' ||
  errorType === 'ESOCKETTIMEDOUT' ||
  errorType === 'ECONNRESET' ||
  msgLower.includes('timeout') ||
  msgLower.includes('timed out')
) {
  category = 'timeout';
} else if (errorType === 'invalid_request_error' || (httpCode >= 400 && httpCode < 500)) {
  category = 'invalid_request';
} else if (errorType === 'api_error' || (httpCode >= 500 && httpCode < 600)) {
  category = 'provider_error';
}
console.log(
  `[Call LLM/Anthropic] ERROR after retries â€” category: ${category}, type: ${errorType}, httpCode: ${httpCode}, msg: ${String(errorMessage).substring(0, 200)}`
);
return [{
  json: {
    success: false,
    content: '',
    input_tokens: 0,
    output_tokens: 0,
    cached_input_tokens: 0,
    cache_write_tokens: 0,
    model_used: setInputs.model,
    provider_used: setInputs.provider,
    errors: [`${category}: ${errorMessage}`],
    error: {
      category,
      type: errorType,
      http_code: httpCode,
      message: errorMessage,
      description: errorDescription,
      provider: setInputs.provider,
      model: setInputs.model
    }
  }
}];

// Normalize OpenAI response into provider-agnostic shape
// Mode: Run Once for All Items
// OpenAI's usage.prompt_tokens INCLUDES cached tokens â€” we subtract so
// input_tokens means non-cached only, matching the Anthropic convention.

const openaiResponse = $input.first().json;
const buildRequest = $('Build OpenAI Request').first().json;

const content = openaiResponse.choices?.[0]?.message?.content || '';
const usage = openaiResponse.usage || {};

const promptTokens = usage.prompt_tokens || 0;
const completionTokens = usage.completion_tokens || 0;
const cachedTokens = usage.prompt_tokens_details?.cached_tokens || 0;
const nonCachedInputTokens = Math.max(0, promptTokens - cachedTokens);

const modelUsed = buildRequest.model || openaiResponse.model;

const success = content.length > 0;
const errors = success ? [] : ['Empty response from OpenAI'];

console.log(`[Call LLM/OpenAI] Response: ${content.length} chars | tokens: ${nonCachedInputTokens}in + ${completionTokens}out + ${cachedTokens}cached | model: ${modelUsed}`);

return [{
  json: {
    success,
    content,
    input_tokens: nonCachedInputTokens,
    output_tokens: completionTokens,
    cached_input_tokens: cachedTokens,
    cache_write_tokens: 0,
    model_used: modelUsed,
    provider_used: 'openai',
    errors
  }
}];

// Build Error Response (OpenAI)
// Mode: Run Once for All Items
// Fires when HTTP Request to OpenAI fails after all retries are exhausted.
// Emits the same shape as Normalize OpenAI Response so downstream agents see uniform output.
const errItem = $input.first()?.json || {};
const setInputs = $('Set Inputs').first().json;

const errorType =
  errItem?.error?.type ||
  errItem?.type ||
  'unknown_error';
const errorCode =
  errItem?.error?.code ||
  errItem?.code ||
  '';
const errorMessage =
  errItem?.error?.message ||
  errItem?.message ||
  'Unknown LLM API error';
// n8n wraps provider errors as NodeApiError: the real provider text (e.g. the
// credit/quota message) lands in error.description, not error.message.
const errorDescription =
  errItem?.error?.description ||
  errItem?.description ||
  '';
const httpCode =
  errItem?.error?.httpCode ||
  errItem?.httpCode ||
  errItem?.statusCode ||
  null;

// Match against BOTH message and description.
let category = 'unknown';
const msgLower = `${String(errorMessage)} ${String(errorDescription)}`.toLowerCase();
const codeLower = String(errorCode).toLowerCase();
if (
  codeLower === 'insufficient_quota' ||
  msgLower.includes('insufficient_quota') ||
  msgLower.includes('credit balance') ||
  msgLower.includes('insufficient') ||
  msgLower.includes('billing') ||
  msgLower.includes('quota')
) {
  category = 'insufficient_credit';
} else if (
  errorType === 'invalid_api_key' ||
  codeLower === 'invalid_api_key' ||
  httpCode === 401 ||
  httpCode === 403
) {
  category = 'invalid_api_key';
} else if (
  errorType === 'rate_limit_error' ||
  codeLower === 'rate_limit_exceeded' ||
  httpCode === 429
) {
  category = 'rate_limit';
} else if (
  httpCode === 503 ||
  msgLower.includes('overloaded') ||
  msgLower.includes('engine is currently overloaded')
) {
  category = 'provider_overloaded';
} else if (
  msgLower.includes('timeout') ||
  msgLower.includes('timed out')
) {
  category = 'timeout';
} else if (errorType === 'invalid_request_error' || (httpCode >= 400 && httpCode < 500)) {
  category = 'invalid_request';
} else if (errorType === 'server_error' || errorType === 'api_error' || (httpCode >= 500 && httpCode < 600)) {
  category = 'provider_error';
}

console.log(
  `[Call LLM/OpenAI] ERROR after retries â€” category: ${category}, type: ${errorType}, code: ${errorCode}, httpCode: ${httpCode}, msg: ${String(errorMessage).substring(0, 200)}`
);

return [{
  json: {
    success: false,
    content: '',
    input_tokens: 0,
    output_tokens: 0,
    cached_input_tokens: 0,
    cache_write_tokens: 0,
    model_used: setInputs.model,
    provider_used: setInputs.provider,
    errors: [`${category}: ${errorMessage}`],
    error: {
      category,
      type: errorType,
      http_code: httpCode,
      message: errorMessage,
      description: errorDescription,
      provider: setInputs.provider,
      model: setInputs.model
    }
  }
}];

// Build Gemini Request
// Mode: Run Once for All Items
// Canonical inputs â†’ Google Generative AI generateContent request body.
// Gemini's systemInstruction is separate from contents (unlike OpenAI/Anthropic).
// Implicit caching is automatic for prompts â‰¥1024 tokens (Flash) / â‰¥4096 (Pro).

const input = $input.first().json;

// Defensive: strip 'models/' prefix if user put one in config
const modelClean = String(input.model || '').replace(/^models\//i, '');

const body = {
  contents: [
    {
      role: 'user',
      parts: [{ text: input.user_message }]
    }
  ],
  systemInstruction: {
    parts: [{ text: input.system }]
  },
  generationConfig: {
    maxOutputTokens: input.max_tokens
  }
};

console.log(`[Call LLM/Gemini] Building request for model: ${modelClean}, system: ${(input.system || '').length} chars, maxOutputTokens: ${input.max_tokens}`);

return [{
  json: {
    request_body: body,
    provider: 'gemini',
    model: modelClean
  }
}];

// Normalize Gemini response into provider-agnostic shape
// Mode: Run Once for All Items
// Gemini's usageMetadata.promptTokenCount INCLUDES cached tokens â€” we subtract
// so input_tokens means non-cached only, matching the convention.
// Prefers buildRequest.model so pricing lookups match config keys
// (Gemini API's modelVersion may include suffixes config doesn't have).

const geminiResponse = $input.first().json;
const buildRequest = $('Build Gemini Request').first().json;

// Gemini returns content as candidates[0].content.parts[*].text
const parts = geminiResponse.candidates?.[0]?.content?.parts || [];
const content = parts.map(p => p?.text || '').join('').trim();

const usage = geminiResponse.usageMetadata || {};
const promptTokens = usage.promptTokenCount || 0;
const completionTokens = usage.candidatesTokenCount || 0;
const cachedTokens = usage.cachedContentTokenCount || 0;
const nonCachedInputTokens = Math.max(0, promptTokens - cachedTokens);

const modelUsed = buildRequest.model || geminiResponse.modelVersion || 'unknown';

const success = content.length > 0;
const errors = success ? [] : ['Empty response from Gemini'];

// Surface non-STOP finish reasons (SAFETY, MAX_TOKENS, RECITATION, etc.)
const finishReason = geminiResponse.candidates?.[0]?.finishReason;
if (finishReason && finishReason !== 'STOP') {
  errors.push(`Gemini finishReason: ${finishReason}`);
}

console.log(`[Call LLM/Gemini] Response: ${content.length} chars | tokens: ${nonCachedInputTokens}in + ${completionTokens}out + ${cachedTokens}cached | model: ${modelUsed} | finish: ${finishReason || 'unknown'}`);

return [{
  json: {
    success,
    content,
    input_tokens: nonCachedInputTokens,
    output_tokens: completionTokens,
    cached_input_tokens: cachedTokens,
    cache_write_tokens: 0,
    model_used: modelUsed,
    provider_used: 'gemini',
    errors
  }
}];

// Build Error Response (Gemini)
// Mode: Run Once for All Items
// Fires when HTTP Request to Gemini fails after all retries are exhausted.
// Emits the same shape as Normalize Gemini Response so downstream agents see uniform output.
const errItem = $input.first()?.json || {};
const setInputs = $('Set Inputs').first().json;

const errorStatus =
  errItem?.error?.status ||
  errItem?.status ||
  '';
const errorMessage =
  errItem?.error?.message ||
  errItem?.message ||
  'Unknown LLM API error';
// n8n wraps provider errors as NodeApiError: the real provider text (e.g. the
// quota/credit message) lands in error.description, not error.message.
const errorDescription =
  errItem?.error?.description ||
  errItem?.description ||
  '';
const httpCode =
  errItem?.error?.httpCode ||
  errItem?.httpCode ||
  errItem?.statusCode ||
  null;

// Match against BOTH message and description.
let category = 'unknown';
const msgLower = `${String(errorMessage)} ${String(errorDescription)}`.toLowerCase();
const statusUpper = String(errorStatus).toUpperCase();
const isResourceExhausted = statusUpper === 'RESOURCE_EXHAUSTED' || httpCode === 429;
if (
  msgLower.includes('credit balance') ||
  msgLower.includes('insufficient') ||
  msgLower.includes('billing') ||
  msgLower.includes('quota')
) {
  category = 'insufficient_credit';
} else if (
  statusUpper === 'UNAUTHENTICATED' ||
  statusUpper === 'PERMISSION_DENIED' ||
  httpCode === 401 ||
  httpCode === 403
) {
  category = 'invalid_api_key';
} else if (isResourceExhausted) {
  category = 'rate_limit';
} else if (
  httpCode === 503 ||
  statusUpper === 'UNAVAILABLE' ||
  msgLower.includes('overloaded')
) {
  category = 'provider_overloaded';
} else if (
  httpCode === 504 ||
  statusUpper === 'DEADLINE_EXCEEDED' ||
  msgLower.includes('timeout') ||
  msgLower.includes('timed out')
) {
  category = 'timeout';
} else if (statusUpper === 'INVALID_ARGUMENT' || (httpCode >= 400 && httpCode < 500)) {
  category = 'invalid_request';
} else if (httpCode >= 500 && httpCode < 600) {
  category = 'provider_error';
}

console.log(
  `[Call LLM/Gemini] ERROR after retries â€” category: ${category}, status: ${errorStatus}, httpCode: ${httpCode}, msg: ${String(errorMessage).substring(0, 200)}`
);

return [{
  json: {
    success: false,
    content: '',
    input_tokens: 0,
    output_tokens: 0,
    cached_input_tokens: 0,
    cache_write_tokens: 0,
    model_used: setInputs.model,
    provider_used: setInputs.provider,
    errors: [`${category}: ${errorMessage}`],
    error: {
      category,
      type: errorStatus,
      http_code: httpCode,
      message: errorMessage,
      description: errorDescription,
      provider: setInputs.provider,
      model: setInputs.model
    }
  }
}];
